-- Ken's Hardened V2 Fix

local b64_0xlIlI1I = {}
local char_0xllIIlI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xlllll1=1,#char_0xllIIlI do b64_0xlIlI1I[char_0xllIIlI:sub(i_0xlllll1,i_0xlllll1)] = i_0xlllll1 - 1 end

function b64_0xlIlI1I.dec_0xIlllI1(d_0xIllIll)
    d_0xIllIll = string.gsub(d_0xIllIll, '[^'..char_0xllIIlI..'=]', '')
    local r_0xllIlIl = {}
    for i_0xlllll1=1, #d_0xIllIll, 4 do
        local c_0xl1I111 = b64_0xlIlI1I[d_0xIllIll:sub(i_0xlllll1,i_0xlllll1)] or 0
        local c_0xIlIlll = b64_0xlIlI1I[d_0xIllIll:sub(i_0xlllll1+1,i_0xlllll1+1)] or 0
        local c_0xlIII1l, c_0xIIllII = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIllIll:sub(i_0xlllll1+2,i_0xlllll1+2)
        if ch3 == "=" then has3 = false else c_0xlIII1l = b64_0xlIlI1I[ch3] or 0 end
        local ch4 = d_0xIllIll:sub(i_0xlllll1+3,i_0xlllll1+3)
        if ch4 == "=" then has4 = false else c_0xIIllII = b64_0xlIlI1I[ch4] or 0 end
        local b_0xI11lII = c_0xl1I111 * (2^18) + c_0xIlIlll * (2^12) + c_0xlIII1l * (2^6) + c_0xIIllII
        local b_0xIl1l11 = math.floor(b_0xI11lII / (2^16)) % (2^8)
        local b_0x11IIlI = math.floor(b_0xI11lII / (2^8)) % (2^8)
        local b_0xIIIIl1 = b_0xI11lII % (2^8)
        table.insert(r_0xllIlIl, string.char(b_0xIl1l11))
        if has3 then table.insert(r_0xllIlIl, string.char(b_0x11IIlI)) end
        if has4 then table.insert(r_0xllIlIl, string.char(b_0xIIIIl1)) end
    end
    return table.concat(r_0xllIlIl)
end


local function bxor_0xIII1ll(a_0xl1IlII,b_0xlIII1l)
    if bit32 then return bit32.bxor(a_0xl1IlII,b_0xlIII1l) end
    local r_0x1lll1I = 0
    for i_0xll1lII = 0, 7 do
        local x_0xIl1ll1 = a_0xl1IlII % 2
        local y_0x1IllIl = b_0xlIII1l % 2
        if x_0xIl1ll1 ~= y_0x1IllIl then r_0x1lll1I = r_0x1lll1I + (2^i_0xll1lII) end
        a_0xl1IlII = math.floor(a_0xl1IlII / 2)
        b_0xlIII1l = math.floor(b_0xlIII1l / 2)
    end
    return r_0x1lll1I
end


local function bxor_str_0xIll1Il(s_0xll11Il, k_0x111IlI)
    local r_0xIll1I1 = {}
    for i_0xIIlI1l=1, #s_0xll11Il do
        local b_0xlIlIIl = string.byte(s_0xll11Il, i_0xIIlI1l)
        local kb_0xlIIlIl = string.byte(k_0x111IlI, (i_0xIIlI1l-1) % #k_0x111IlI + 1)
        r_0xIll1I1[i_0xIIlI1l] = string.char(bxor_0xIII1ll(b_0xlIlIIl, kb_0xlIIlIl))
    end
    return table.concat(r_0xIll1I1)
end


local function getkeys_0x1llI11()
    local seed = b64_0xlIlI1I.dec_0xIlllI1("M3FrdGt3eFU=")
    local k1_enc = b64_0xlIlI1I.dec_0xIlllI1("eT9aRwYVCy0=")
    local k2_enc = b64_0xlIlI1I.dec_0xIlllI1("ajAPGSodGgI=")
    return bxor_str_0xIll1Il(k1_enc, seed), bxor_str_0xIll1Il(k2_enc, seed)
end


local function cff_0xlllIlI(a_0xIIIIlI)
    local st_0xI1IlI1 = 0
    local res_0xIl1IlI = a_0xIIIIlI
    while true do
        if st_0xI1IlI1 == 0 then
            res_0xIl1IlI = res_0xIl1IlI + 1
            st_0xI1IlI1 = 1
        elseif st_0xI1IlI1 == 1 then
            res_0xIl1IlI = res_0xIl1IlI * 2
            st_0xI1IlI1 = 2
        elseif st_0xI1IlI1 == 2 then
            res_0xIl1IlI = res_0xIl1IlI - 3
            st_0xI1IlI1 = 3
        else
            break
        end
    end
    return res_0xIl1IlI
end


local function chain_0xllIIII(x) return x*2 end
local function chain_0xIIl1ll(x) return chain_0xllIIII(x)+1 end


local d_0xIIII1l = {
  {op=255, val="", is_enc=true},
}
local pc_0xII1llI = 1
local stk_0xl11Ill = {}
stk_0xl11Ill._jmp = nil


local disp_0x1ll1ll = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0x1llI11()

local state_0x1Il1II = 0
while true do
    if state_0x1Il1II == 0 then  -- FETCH
        if pc_0xII1llI > #d_0xIIII1l then break end
        local inst = d_0xIIII1l[pc_0xII1llI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlIlI1I.dec_0xIlllI1(val)
            d = bxor_str_0xIll1Il(d, k2)
            val = bxor_str_0xIll1Il(d, k1)
        end
        stk_0xl11Ill._jmp = nil
        pc_0xII1llI = pc_0xII1llI + 1
        cur_op_0xIII11l = opcode
        cur_val_0xlII1l1 = val
        state_0x1Il1II = 1

    elseif state_0x1Il1II == 1 then  -- EXECUTE
        local handler = disp_0x1ll1ll[cur_op_0xIII11l]
        if handler then
            handler(stk_0xl11Ill, cur_val_0xlII1l1)
        end
        if stk_0xl11Ill._jmp then
            pc_0xII1llI = pc_0xII1llI + stk_0xl11Ill._jmp
        end
        state_0x1Il1II = 0
